export interface AuthBody {
  nick: string;
  password: string;
}

export interface AuthResponse {
  user: {
    id: number;
    nick: string;
  };
  accessToken: string;
}

export interface GameInfoResponse {
  time: number;
  map: Map;
  humans: Human[];
}

export interface Map {
  seed: number;
  sizeX: number;
  sizeY: number;
}

export interface Human {
  id: number;
  posX: number;
  posY: number;
}

export enum AuthError {
  userAlreadyTaken = 'User already taken',
  invalidCredentials = 'Invalid credentials',
  emptyNick = 'Empty nick',
  tooShortNick = 'Too short nick',
  tooLongNick = 'Too long nick',
  nickIncorrectCharacter = 'Nick incorrect character',
  emptyPassword = 'Empty password',
  passwordTooWeak = 'Password too weak',
}
